import { Linking } from 'react-native';
import { NavigationContainerRef } from '@react-navigation/native';

const VALID_HOSTS = ['myapp://'];
const VALID_PATHS = ['/profile/', '/payment/'];
const VALID_PAYMENT_ACTIONS = ['confirm', 'cancel', 'success'];

let navigationRef = null;

const setNavigationRef = (ref) => {
  navigationRef = ref;
};

const isValidHost = (url) => {
  return VALID_HOSTS.some(host => url.startsWith(host));
};

const isValidPath = (url) => {
  return VALID_PATHS.some(path => url.includes(path));
};

const validateId = (id) => {
  if (!id || typeof id !== 'string') return false;
  return /^\d+$/.test(id.trim());
};

const validatePaymentAction = (action) => {
  return VALID_PAYMENT_ACTIONS.includes(action);
};

const parseDeepLink = (url) => {
  try {
    if (!isValidHost(url) || !isValidPath(url)) {
      throw new Error('Invalid host or path');
    }

    const urlObj = new URL(url);
    const path = urlObj.pathname;
    const params = new URLSearchParams(urlObj.search);

    let route = '';
    let paramsObj = {};

    if (path.startsWith('/profile/')) {
      const id = path.split('/profile/')[1];
      if (!validateId(id)) {
        throw new Error('Invalid profile ID');
      }
      route = 'Profile';
      paramsObj = { id: parseInt(id) };
    } else if (path.startsWith('/payment/')) {
      const action = path.split('/payment/')[1];
      if (!validatePaymentAction(action)) {
        throw new Error('Invalid payment action');
      }
      route = 'Payment';
      paramsObj = { action };
    }

    return { route, params: paramsObj };
  } catch (error) {
    console.error('Deep link parsing error:', error);
    return null;
  }
};

const handleDeepLink = async (url) => {
  if (!url || typeof url !== 'string') return;

  const parsed = parseDeepLink(url);
  if (!parsed || !parsed.route || !navigationRef) return;

  try {
    await navigationRef.navigate(parsed.route, parsed.params);
  } catch (error) {
    console.error('Navigation error:', error);
  }
};

const initializeDeepLinking = () => {
  Linking.addEventListener('url', ({ url }) => {
    handleDeepLink(url);
  });

  Linking.getInitialURL().then((url) => {
    if (url) {
      handleDeepLink(url);
    }
  });
};

